import './Tag.scss';

import { IconButton } from ':components/IconButton';
import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont';
import React from 'react';
import { Typography } from '../Typography';
import type { TagProps } from './Tag.types';

export const Tag: React.FC<TagProps> = ({
	label,
	onRemove,
	onClick,
	removeAriaLabel,
	className,
	dataTestId = 'Tag',
	...rest
}) => {
	const handleClick = (event: React.MouseEvent<HTMLDivElement>): void => {
		onClick?.(event);
	};

	const handleRemoveClick = (event: React.MouseEvent<HTMLButtonElement>): void => {
		event.stopPropagation();

		onRemove?.();
	};

	const generatedRemoveAriaLabel = typeof label === 'string' ? `Удалить тег ${label}` : 'Удалить тег';

	return (
		<div
			{...rest}
			data-testid={dataTestId}
			onClick={onClick ? handleClick : undefined}
			className={classNames('dsb_tag', className)}
		>
			<Typography variant="body3" className="dsb_tag-label">
				{label}
			</Typography>

			<IconButton
				size="medium"
				iconName={Icons.Close}
				className="dsb_tag-close-icon"
				onClick={handleRemoveClick}
				aria-label={removeAriaLabel ?? generatedRemoveAriaLabel}
			/>
		</div>
	);
};
